UPDATE human_conditions SET affected_region_ids = '{pancreas,uterus,placenta}', category = 'gynecological' WHERE slug = 'gestational-diabetes';
UPDATE human_conditions SET affected_region_ids = '{placenta,kidneys,medulla,hypothalamus}', category = 'gynecological' WHERE slug = 'preeclampsia';
UPDATE human_conditions SET affected_region_ids = '{stomach,medulla,hypothalamus}', category = 'gynecological' WHERE slug = 'hyperemesis-gravidarum';
